void InitPerRun(int size, float *m) {
    int i;
    for (i=0; i<size*size; i++)
        *(m+i) = 0.0;
}

void BackSub(float *a, float *b, float *finalVec, int size) {
    int i,j;
    for(i=0;i<size;i++){
        finalVec[size-i-1]=b[size-i-1];
        for(j=0;j<i;j++) {
            finalVec[size-i-1]-=*(a+size*(size-i-1)+(size-j-1)) * finalVec[size-j-1];
        }
        finalVec[size-i-1]=finalVec[size-i-1]/ *(a+size*(size-i-1)+(size-i-1));
    }
}

void InitMat(FILE *fp, int size, float *ary, int nrow, int ncol) {
    int i, j;
    for (i=0; i<nrow; i++) {
        for (j=0; j<ncol; j++) {
            fscanf(fp, "%f",  ary+size*i+j);
        }
    }
}

void InitAry(FILE *fp, float *ary, int ary_size) {
    int i;
    for (i=0; i<ary_size; i++) {
        fscanf(fp, "%f",  &ary[i]);
    }
}

void PrintMat(float *ary, int size, int nrow, int ncol) {
    int i, j;
    for (i=0; i<nrow; i++) {
        for (j=0; j<ncol; j++) {
            printf("%8.2e ", *(ary+size*i+j));
        }
        printf("\n");
    }
    printf("\n");
}

void PrintAry(float *ary, int ary_size) {
    int i;
    for (i=0; i<ary_size; i++) {
        printf("%.2e ", ary[i]);
    }
    printf("\n\n");
}

void create_matrix(float *m, int size){
  int i,j;
  float lamda = -0.01;
  float coe[2*size-1];
  float coe_i =0.0;

  for (i=0; i < size; i++) {
      coe_i = 10*exp(lamda*i);
      j=size-1+i;
      coe[j]=coe_i;
      j=size-1-i;
      coe[j]=coe_i;
  }

  for (i=0; i < size; i++) {
      for (j=0; j < size; j++) {
        m[i*size+j]=coe[size-1-i+j];
      }
  }
}

// CUDA Kernel Definitions
__global__ void Fan1_kernel(float *m_dev, float *a_dev, float *b_dev, const int size, const int t) {
    int globalId = blockIdx.x * blockDim.x + threadIdx.x;

    if (globalId < size-1-t) {
         *(m_dev + size * (globalId + t + 1)+t) = *(a_dev + size * (globalId + t + 1) + t) / *(a_dev + size * t + t);
    }
}

__global__ void Fan2_kernel(float *m_dev, float *a_dev, float *b_dev, const int size, const int t) {
    int globalIdx = blockIdx.x * blockDim.x + threadIdx.x;
    int globalIdy = blockIdx.y * blockDim.y + threadIdx.y;

    if (globalIdx < size-1-t && globalIdy < size-t) {
        a_dev[size*(globalIdx+1+t)+(globalIdy+t)] -= m_dev[size*(globalIdx+1+t)+t] * a_dev[size*t+(globalIdy+t)];

        if(globalIdy == 0){
            b_dev[globalIdx+1+t] -= m_dev[size*(globalIdx+1+t)+(globalIdy+t)] * b_dev[t];
        }
    }
}

// Timing helper
double eventTime(cudaEvent_t start, cudaEvent_t end) {
    float milliseconds = 0;
    cudaEventRecord(end);
    cudaEventSynchronize(end);
    cudaEventElapsedTime(&milliseconds, start, end);
    return milliseconds / 1000.0;
}

void ForwardSub(float *a, float *b, float *m, int size, int timing) {
    float *d_a, *d_b, *d_m;
    size_t a_size = sizeof(float) * size * size;
    size_t b_size = sizeof(float) * size;
    size_t m_size = sizeof(float) * size * size;

    // Allocate device memory
    cudaMalloc(&d_a, a_size);
    cudaMalloc(&d_b, b_size);
    cudaMalloc(&d_m, m_size);

    // Copy input data to device
    cudaMemcpy(d_a, a, a_size, cudaMemcpyHostToDevice);
    cudaMemcpy(d_b, b, b_size, cudaMemcpyHostToDevice);
    cudaMemcpy(d_m, m, m_size, cudaMemcpyHostToDevice);

    // Define block and grid sizes
    int block_size_0 = 256; // Default fallback if not defined
    int block_size_1_x = 16;
    int block_size_1_y = 16;

    dim3 block1(block_size_0);
    dim3 block2(block_size_1_x, block_size_1_y);

    dim3 grid1((size + block_size_0 - 1) / block_size_0);
    dim3 grid2((size + block_size_1_x - 1) / block_size_1_x, (size + block_size_1_y - 1) / block_size_1_y);

    cudaEvent_t start, stop;
    cudaEventCreate(&start);
    cudaEventCreate(&stop);

    int t;
    for (t=0; t<(size-1); t++) {
        if (timing) cudaEventRecord(start);

        // Launch Fan1
        Fan1_kernel<<<grid1, block1>>>(d_m, d_a, d_b, size, t);

        // Launch Fan2
        Fan2_kernel<<<grid2, block2>>>(d_m, d_a, d_b, size, t);

        if (timing) {
            cudaEventRecord(stop);
            cudaEventSynchronize(stop);
            float ms = 0;
            cudaEventElapsedTime(&ms, start, stop);
            printf("Iteration %d: %f ms\n", t, ms);
        }
    }

    // Copy results back to host
    cudaMemcpy(a, d_a, a_size, cudaMemcpyDeviceToHost);
    cudaMemcpy(b, d_b, b_size, cudaMemcpyDeviceToHost);
    cudaMemcpy(m, d_m, m_size, cudaMemcpyDeviceToHost);

    // Cleanup
    cudaFree(d_a);
    cudaFree(d_b);
    cudaFree(d_m);
    cudaEventDestroy(start);
    cudaEventDestroy(stop);
}

int main(int argc, char *argv[]) {
    printf("WG size of kernel 1 = %d, WG size of kernel 2= %d X %d\n", 256, 16, 16);
    float *a=NULL, *b=NULL, *finalVec=NULL;
    float *m=NULL;
    int size = -1;

    FILE *fp;
    char filename[200];
    int show_data=0, quiet=0, timing=0, platform=0, device=0;

    if (parseCommandline(argc, argv, filename, &quiet, &show_data, &timing, &platform, &device, &size)) {
        printUsage();
        return 0;
    }

    if(size < 1) {
        fp = fopen(filename, "r");
        if (!fp) {
            printf("Error opening file: %s\n", filename);
            return -1;
        }
        fscanf(fp, "%d", &size);

        a = (float *) malloc(size * size * sizeof(float));
        InitMat(fp, size, a, size, size);

        b = (float *) malloc(size * sizeof(float));
        InitAry(fp, b, size);

        fclose(fp);
    } else {
        printf("create input internally before create, size = %d \n", size);
        a = (float *) malloc(size * size * sizeof(float));
        create_matrix(a, size);

        b = (float *) malloc(size * sizeof(float));
        for (int i=0; i< size; i++)
            b[i]=1.0;
    }

    if (!quiet && show_data) {
        printf("The input matrix a is:\n");
        PrintMat(a, size, size, size);
        printf("The input array b is:\n");
        PrintAry(b, size);
    }

    m = (float *) malloc(size * size * sizeof(float));
    finalVec = (float *) malloc(size * sizeof(float));

    InitPerRun(size, m);

    ForwardSub(a, b, m, size, timing);

    if (!quiet && show_data) {
        printf("The result of matrix m is: \n");
        PrintMat(m, size, size, size);
        printf("The result of matrix a is: \n");
        PrintMat(a, size, size, size);
        printf("The result of array b is: \n");
        PrintAry(b, size);

        BackSub(a, b, finalVec, size);
        printf("The final solution is: \n");
        PrintAry(finalVec, size);
    }

    free(m);
    free(a);
    free(b);
    free(finalVec);

    return 0;
}
